#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int a[maxn],k[maxn],dp[maxn],dq[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,q;
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	cin>>q;
	for(int i=1,k; i<=q; i++) {
		cin>>k;
		int h=1,t=0;
		dq[++t]=1;
		for(int i=2; i<=n; i++) {
			while(h<t&&dq[h]<i-k) {
				h++;
			}
			int u=dq[h];
			if(a[u]>a[i]){
				dp[i]=dp[u];
			}else{
				dp[i]=dp[u]+1;
			}
			while(h<=t) {
				int v=dq[t];
				if(dp[v]>dp[i]||(dp[v]==dp[i]&&a[v]<=a[i])){
					t--;
				}else{
					break;
				}
			}
			dq[++t]=i;
		}
		cout<<dp[n]<<"\n";
	}
	return 0;
}
